diff --git a/regexp.go b/regexp.go
index e0bcff6..76cb5d6 100644
--- a/regexp.go
+++ b/regexp.go
@@ -218,6 +218,13 @@ func (r *routeRegexp) url(values map[string]string) (string, error) {
 		}
 		if r.regexpType == regexpTypeQuery {
 			value = url.QueryEscape(value)
+		} else if (r.regexpType == regexpTypePath || r.regexpType == regexpTypePrefix) && !r.options.useEncodedPath {
+			// PathEscape percent-encodes reserved characters (?, #, space, etc.)
+			// but also encodes / which may be a valid separator inside a path
+			// variable pattern. Re-expand %2F so the path structure is preserved.
+			// Skip encoding when useEncodedPath is true: the caller is expected to
+			// supply already-encoded values in that mode.
+			value = strings.ReplaceAll(url.PathEscape(value), "%2F", "/")
 		}
 		urlValues[k] = value
 	}
